// Define critical services and their health endpoints
const services = [
  {
    name: 'MAS Orchestrator',
    health_url: 'http://192.168.0.188:8001/health',
    restart_cmd: 'docker restart myca-orchestrator-new',
    vm: '188',
    max_restart_attempts: 3,
    cooldown_minutes: 5
  },
  {
    name: 'MINDEX API',
    health_url: 'http://192.168.0.189:8000/health',
    restart_cmd: 'docker restart mindex-api',
    vm: '189',
    max_restart_attempts: 3,
    cooldown_minutes: 5
  },
  {
    name: 'n8n',
    health_url: 'http://192.168.0.188:5678/healthz',
    restart_cmd: 'docker restart mycosoft-mas-n8n-1',
    vm: '188',
    max_restart_attempts: 2,
    cooldown_minutes: 10
  },
  {
    name: 'Website',
    health_url: 'http://192.168.0.187:3000',
    restart_cmd: 'docker restart mycosoft-website',
    vm: '187',
    max_restart_attempts: 3,
    cooldown_minutes: 5
  }
];

return services.map(s => ({ json: s }));

const items = $input.all();
const now = Date.now();
const healActions = [];
const healthy = [];

// Simple in-memory tracker (resets on n8n restart — acceptable for auto-healing)
if (!globalThis._autoHealState) {
  globalThis._autoHealState = {};
}

for (const item of items) {
  const service = item.json;
  const name = service.name || 'unknown';
  const statusCode = service.statusCode || 0;
  const isHealthy = statusCode >= 200 && statusCode < 500;

  if (!globalThis._autoHealState[name]) {
    globalThis._autoHealState[name] = { attempts: 0, last_restart: 0 };
  }
  const state = globalThis._autoHealState[name];

  if (isHealthy) {
    state.attempts = 0; // Reset on healthy
    healthy.push({ name, status: 'healthy', code: statusCode });
  } else {
    const cooldownMs = (service.cooldown_minutes || 5) * 60 * 1000;
    const withinCooldown = (now - state.last_restart) < cooldownMs;
    const maxAttempts = service.max_restart_attempts || 3;

    if (state.attempts < maxAttempts && !withinCooldown) {
      state.attempts++;
      state.last_restart = now;
      healActions.push({
        name,
        action: 'restart',
        vm: service.vm,
        restart_cmd: service.restart_cmd,
        attempt: state.attempts,
        max_attempts: maxAttempts
      });
    } else if (state.attempts >= maxAttempts) {
      healActions.push({
        name,
        action: 'escalate',
        vm: service.vm,
        message: `${name} failed ${state.attempts} restart attempts — needs manual intervention`,
        attempt: state.attempts
      });
    }
  }
}

const result = {
  timestamp: new Date().toISOString(),
  healthy: healthy,
  actions: healActions,
  needs_healing: healActions.length > 0,
  needs_escalation: healActions.some(a => a.action === 'escalate')
};

return [{ json: result }];
